+#[pyfunction]
+#[pyo3(signature = (base, drop_names, usemask=true, asrecarray=false))]
+fn recfunctions_drop_fields(
+    py: Python<'_>,
+    base: Py<PyAny>,
+    drop_names: Py<PyAny>,
+    usemask: bool,
+    asrecarray: bool,
+) -> PyResult<Py<PyAny>> {
+    // Passthrough to numpy.lib.recfunctions.drop_fields. Returns a copy
+    // of the structured array with the named fields removed. Matches
+    // numpy on string-or-list drop_names, nested field access via dot
+    // notation, usemask flag, and asrecarray flag.
+    let numpy = py.import("numpy")?;
+    let kwargs = PyDict::new(py);
+    kwargs.set_item("usemask", usemask)?;
+    kwargs.set_item("asrecarray", asrecarray)?;
+    Ok(numpy
+        .getattr("lib")?
+        .getattr("recfunctions")?
+        .getattr("drop_fields")?
+        .call((base.bind(py), drop_names.bind(py)), Some(&kwargs))?
+        .unbind())
+}
+
+#[pyfunction]
+#[pyo3(signature = (base, namemapper))]
+fn recfunctions_rename_fields(
+    py: Python<'_>,
+    base: Py<PyAny>,
+    namemapper: Py<PyAny>,
+) -> PyResult<Py<PyAny>> {
+    // Passthrough to numpy.lib.recfunctions.rename_fields. Given a dict
+    // mapping old-name -> new-name, returns a structured array with
+    // fields renamed. Matches numpy on nested-structure renames and
+    // no-op dicts.
+    let numpy = py.import("numpy")?;
+    Ok(numpy
+        .getattr("lib")?
+        .getattr("recfunctions")?
+        .getattr("rename_fields")?
+        .call1((base.bind(py), namemapper.bind(py)))?
+        .unbind())
+}
+
+#[pyfunction]
+#[pyo3(signature = (base, names, data, dtypes=None, fill_value=-1_i64, usemask=true, asrecarray=false))]
+#[allow(clippy::too_many_arguments)]
+fn recfunctions_append_fields(
+    py: Python<'_>,
+    base: Py<PyAny>,
+    names: Py<PyAny>,
+    data: Py<PyAny>,
+    dtypes: Option<Py<PyAny>>,
+    fill_value: i64,
+    usemask: bool,
+    asrecarray: bool,
+) -> PyResult<Py<PyAny>> {
+    // Passthrough to numpy.lib.recfunctions.append_fields. Extends a
+    // structured array with one or more additional fields. Matches
+    // numpy on single-name vs list-of-names, dtype coercion, and the
+    // fill_value/usemask/asrecarray flags.
+    let numpy = py.import("numpy")?;
+    let kwargs = PyDict::new(py);
+    if let Some(dtypes_val) = dtypes {
+        kwargs.set_item("dtypes", dtypes_val.bind(py))?;
+    }
+    kwargs.set_item("fill_value", fill_value)?;
+    kwargs.set_item("usemask", usemask)?;
+    kwargs.set_item("asrecarray", asrecarray)?;
+    Ok(numpy
+        .getattr("lib")?
+        .getattr("recfunctions")?
+        .getattr("append_fields")?
+        .call(
+            (base.bind(py), names.bind(py), data.bind(py)),
+            Some(&kwargs),
+        )?
+        .unbind())
+}
+
+#[pyfunction]
+#[pyo3(signature = (seqarrays, fill_value=-1_i64, flatten=false, usemask=false, asrecarray=false))]
+fn recfunctions_merge_arrays(
+    py: Python<'_>,
+    seqarrays: Py<PyAny>,
+    fill_value: i64,
+    flatten: bool,
+    usemask: bool,
+    asrecarray: bool,
+) -> PyResult<Py<PyAny>> {
+    // Passthrough to numpy.lib.recfunctions.merge_arrays. Merges a
+    // sequence of (structured or plain) arrays side-by-side. Matches
+    // numpy on flatten/usemask/asrecarray flags and on varying-length
+    // inputs filled with fill_value.
+    let numpy = py.import("numpy")?;
+    let kwargs = PyDict::new(py);
+    kwargs.set_item("fill_value", fill_value)?;
+    kwargs.set_item("flatten", flatten)?;
+    kwargs.set_item("usemask", usemask)?;
+    kwargs.set_item("asrecarray", asrecarray)?;
+    Ok(numpy
+        .getattr("lib")?
+        .getattr("recfunctions")?
+        .getattr("merge_arrays")?
+        .call((seqarrays.bind(py),), Some(&kwargs))?
+        .unbind())
+}
+
+#[pyfunction]
+#[pyo3(signature = (arr, dtype=None, names=None, align=false, copy=false, casting="unsafe"))]
+#[allow(clippy::too_many_arguments)]
+fn recfunctions_unstructured_to_structured(
+    py: Python<'_>,
+    arr: Py<PyAny>,
+    dtype: Option<Py<PyAny>>,
+    names: Option<Py<PyAny>>,
+    align: bool,
+    copy: bool,
+    casting: &str,
+) -> PyResult<Py<PyAny>> {
+    // Passthrough to numpy.lib.recfunctions.unstructured_to_structured.
+    // Converts an N-D unstructured array's trailing axis into named
+    // fields of a structured dtype. Matches numpy on explicit dtype,
+    // autogenerated names, align flag, and casting policy.
+    let numpy = py.import("numpy")?;
+    let kwargs = PyDict::new(py);
+    if let Some(dtype_val) = dtype {
+        kwargs.set_item("dtype", dtype_val.bind(py))?;
+    }
+    if let Some(names_val) = names {
+        kwargs.set_item("names", names_val.bind(py))?;
+    }
+    kwargs.set_item("align", align)?;
+    kwargs.set_item("copy", copy)?;
+    kwargs.set_item("casting", casting)?;
+    Ok(numpy
+        .getattr("lib")?
+        .getattr("recfunctions")?
+        .getattr("unstructured_to_structured")?
+        .call((arr.bind(py),), Some(&kwargs))?
+        .unbind())
+}
