+    #[test]
+    fn recfunctions_family_matches_numpy_across_drop_rename_append_merge_and_u2s() {
+        with_python(|py| {
+            if !numpy_available(py) {
+                return Ok(());
+            }
+
+            let module = PyModule::new(py, "fnp_python_test")?;
+            fnp_python(&module)?;
+            let drop_fn = module.getattr("recfunctions_drop_fields")?;
+            let rename_fn = module.getattr("recfunctions_rename_fields")?;
+            let append_fn = module.getattr("recfunctions_append_fields")?;
+            let merge_fn = module.getattr("recfunctions_merge_arrays")?;
+            let u2s_fn = module.getattr("recfunctions_unstructured_to_structured")?;
+            let numpy = py.import("numpy")?;
+            let nrf = numpy.getattr("lib")?.getattr("recfunctions")?;
+            let numpy_drop = nrf.getattr("drop_fields")?;
+            let numpy_rename = nrf.getattr("rename_fields")?;
+            let numpy_append = nrf.getattr("append_fields")?;
+            let numpy_merge = nrf.getattr("merge_arrays")?;
+            let numpy_u2s = nrf.getattr("unstructured_to_structured")?;
+
+            // Build a small structured array with fields (a:i8, b:f4, c:i4).
+            let builtins = py.import("builtins")?;
+            let eval_fn = builtins.getattr("eval")?;
+            let globals = PyDict::new(py);
+            globals.set_item("np", numpy.clone())?;
+            let eval_with_globals = |code: &str| -> PyResult<pyo3::Bound<'_, pyo3::types::PyAny>> {
+                eval_fn.call((code, &globals), None::<&pyo3::Bound<'_, PyDict>>)
+            };
+            let src = eval_with_globals(
+                "np.array([(1, 2.0, 10), (3, 4.0, 20), (5, 6.0, 30)], dtype=[('a','i8'),('b','f4'),('c','i4')])",
+            )?;
+
+            // drop_fields: remove a single field.
+            let ours_d = drop_fn.call1((src.clone(), "b"))?;
+            let theirs_d = numpy_drop.call1((src.clone(), "b"))?;
+            assert_array_matches_numpy(&ours_d, &theirs_d)?;
+            assert_eq!(
+                ours_d.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?,
+                theirs_d.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?
+            );
+
+            // drop_fields: remove multiple via list.
+            let ours_dm = drop_fn.call1((src.clone(), vec!["a", "b"]))?;
+            let theirs_dm = numpy_drop.call1((src.clone(), vec!["a", "b"]))?;
+            assert_array_matches_numpy(&ours_dm, &theirs_dm)?;
+
+            // rename_fields: remap names via dict.
+            let rename_map = PyDict::new(py);
+            rename_map.set_item("a", "alpha")?;
+            rename_map.set_item("c", "gamma")?;
+            let ours_r = rename_fn.call1((src.clone(), rename_map.clone()))?;
+            let theirs_r = numpy_rename.call1((src.clone(), rename_map.clone()))?;
+            assert_eq!(
+                ours_r.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?,
+                theirs_r.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?
+            );
+
+            // append_fields: add a new 'd' field of length 3.
+            let ours_a = append_fn.call1((src.clone(), "d", vec![7_i64, 8, 9]))?;
+            let theirs_a = numpy_append.call1((src.clone(), "d", vec![7_i64, 8, 9]))?;
+            assert_array_matches_numpy(&ours_a, &theirs_a)?;
+            assert_eq!(
+                ours_a.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?,
+                theirs_a.getattr("dtype")?.getattr("names")?.extract::<Vec<String>>()?
+            );
+
+            // merge_arrays: combine two structured arrays side-by-side.
+            let second = eval_with_globals(
+                "np.array([(0.5, 'x'), (0.75, 'y'), (1.0, 'z')], dtype=[('w','f8'),('tag','U1')])",
+            )?;
+            let ours_m = merge_fn.call1(((src.clone(), second.clone()),))?;
+            let theirs_m = numpy_merge.call1(((src.clone(), second.clone()),))?;
+            assert_array_matches_numpy(&ours_m, &theirs_m)?;
+
+            // unstructured_to_structured: convert a 3×3 float array to
+            // a 1-D structured array with 3 fields.
+            let unstructured = eval_with_globals(
+                "np.arange(9, dtype='f4').reshape(3, 3)",
+            )?;
+            let dtype_spec = eval_with_globals(
+                "np.dtype([('x','f4'),('y','f4'),('z','f4')])",
+            )?;
+            let dkw = PyDict::new(py);
+            dkw.set_item("dtype", dtype_spec.clone())?;
+            let ours_u2s = u2s_fn.call((unstructured.clone(),), Some(&dkw))?;
+            let theirs_u2s = numpy_u2s.call((unstructured.clone(),), Some(&dkw))?;
+            assert_array_matches_numpy(&ours_u2s, &theirs_u2s)?;
+
+            Ok(())
+        });
+    }
 }
